using System.Runtime.CompilerServices;
using BenchmarkDotNet.Attributes;
using BenchmarkDotNet.Configs;

namespace ConstExpr.Benchmarks.MathTests;

/// <summary>
/// Compares Math.Truncate / MathF.Truncate against several scalar alternatives (no SIMD).
///
/// Candidates tested:
///   DotNet       – Math.Truncate / MathF.Truncate         (single hardware instruction: FRINTZ/ROUNDSS mode-3)
///   BitManip     – FastTruncate bit-manipulation           (was generated by TruncateFunctionOptimizer before this benchmark)
///   IntCast      – (float)(int)x / (double)(long)x         (FP→INT→FP round-trip; truncates toward zero; safe for |x| &lt; 2^31/2^52)
///   GenericMath  – float.Truncate / double.Truncate        (IFloatingPoint&lt;T&gt; generic-math path; JIT devirtualises to same instruction)
///
/// All data is drawn from the safe range [-1e8, 1e8] so that IntCast / LongCast never overflow,
/// keeping the comparison fair.
///
/// Benchmark results (Apple M4 Pro, .NET 10.0.1, ARM64 RyuJIT armv8.0-a):
///
///   Double group (baseline = DotNet_Double):
///     DotNet_Double      0.542 ns  ratio 1.00  ← WINNER: single FRINTZ instruction
///     GenericMath_Double 0.555 ns  ratio 1.02  ≈ same instruction via IFloatingPoint&lt;T&gt;
///     LongCast_Double    0.609 ns  ratio 1.12  FP/int domain crossing — avoid
///     BitManip_Double    0.629 ns  ratio 1.16  bit manipulation overhead — SLOWEST, avoid
///
///   Float group (baseline = DotNet_Float):
///     DotNet_Float       0.559 ns  ratio 1.00  ← WINNER: single FRINTZ instruction
///     GenericMath_Float  0.562 ns  ratio 1.01  ≈ tied
///     IntCast_Float      0.615 ns  ratio 1.10  FP/int domain crossing — avoid
///     BitManip_Float     0.693 ns  ratio 1.24  bit manipulation overhead — SLOWEST, avoid
///
/// Conclusion:
///   Math.Truncate / MathF.Truncate is the fastest scalar implementation.
///   The hardware FRINTZ/ROUNDSS instruction cannot be beaten by software.
///   The custom FastTruncate bit-manipulation in TruncateFunctionOptimizer has been removed;
///   float/double now fall through to the direct float.Truncate / double.Truncate call.
///
/// Run command:
///   dotnet run -c Release --project ConstExpr.Benchmarks/ConstExpr.Benchmarks.csproj --filter '*TruncateBenchmark*'
/// </summary>
[MemoryDiagnoser]
[GroupBenchmarksBy(BenchmarkLogicalGroupRule.ByCategory)]
[CategoriesColumn]
public class TruncateBenchmark
{
    private const int N = 1_024;
    private float[] _floatData = null!;
    private double[] _doubleData = null!;

    [GlobalSetup]
    public void Setup()
    {
        var rng = new Random(42);
        _floatData = new float[N];
        _doubleData = new double[N];

        for (var i = 0; i < N; i++)
        {
            // Mix positive/negative values with fractional parts, within safe range for cast impls.
            var v = (rng.NextDouble() * 2.0 - 1.0) * 1e8;
            _floatData[i] = (float)v;
            _doubleData[i] = v;
        }
    }

    // ── float ──────────────────────────────────────────────────────────────

    /// <summary>
    /// Built-in MathF.Truncate — single hardware instruction: FRINTZ (ARM64) / ROUNDSS imm8=3 (x64).
    /// Handles NaN, infinity, and the full float range correctly.
    /// </summary>
    [Benchmark(Baseline = true, OperationsPerInvoke = N)]
    [BenchmarkCategory("Float")]
    public float DotNet_Float()
    {
        var sum = 0f;
        foreach (var v in _floatData)
            sum += MathF.Truncate(v);
        return sum;
    }

    /// <summary>
    /// Current TruncateFunctionOptimizer output: bit-manipulation via BitConverter.
    /// Extracts sign + exponent, then masks off fractional mantissa bits.
    /// Contains two conditional branches (exponent &lt; 0 and exponent &gt;= 23).
    /// </summary>
    [Benchmark(OperationsPerInvoke = N)]
    [BenchmarkCategory("Float")]
    public float BitManip_Float()
    {
        var sum = 0f;
        foreach (var v in _floatData)
            sum += FastTruncateFloat(v);
        return sum;
    }

    /// <summary>
    /// Integer-cast round-trip: (float)(int)x.
    /// FCVTZS (FP → int, truncate toward zero) + SCVTF (int → FP).
    /// Semantically correct for |x| &lt; 2^31 (no NaN/Inf safety).
    /// Two-instruction path vs one for the baseline.
    /// </summary>
    [Benchmark(OperationsPerInvoke = N)]
    [BenchmarkCategory("Float")]
    public float IntCast_Float()
    {
        var sum = 0f;
        foreach (var v in _floatData)
        {
            var t = (int)v;   // FCVTZS: truncate toward zero
            sum += t;         // widening int → float (SCVTF)
        }
        return sum;
    }

    /// <summary>
    /// Generic-math path: float.Truncate via IFloatingPoint&lt;T&gt;.
    /// JIT devirtualises to the same FRINTZ/ROUNDSS instruction as MathF.Truncate.
    /// </summary>
    [Benchmark(OperationsPerInvoke = N)]
    [BenchmarkCategory("Float")]
    public float GenericMath_Float()
    {
        var sum = 0f;
        foreach (var v in _floatData)
            sum += float.Truncate(v);
        return sum;
    }

    // ── double ─────────────────────────────────────────────────────────────

    /// <summary>
    /// Built-in Math.Truncate — single hardware instruction: FRINTZ (ARM64) / ROUNDSD imm8=3 (x64).
    /// Handles NaN, infinity, and the full double range correctly.
    /// </summary>
    [Benchmark(Baseline = true, OperationsPerInvoke = N)]
    [BenchmarkCategory("Double")]
    public double DotNet_Double()
    {
        var sum = 0.0;
        foreach (var v in _doubleData)
            sum += Math.Truncate(v);
        return sum;
    }

    /// <summary>
    /// Current TruncateFunctionOptimizer output: bit-manipulation via BitConverter.
    /// Extracts sign + exponent, then masks off fractional mantissa bits.
    /// Contains two conditional branches (exponent &lt; 0 and exponent &gt;= 52).
    /// </summary>
    [Benchmark(OperationsPerInvoke = N)]
    [BenchmarkCategory("Double")]
    public double BitManip_Double()
    {
        var sum = 0.0;
        foreach (var v in _doubleData)
            sum += FastTruncateDouble(v);
        return sum;
    }

    /// <summary>
    /// Long-cast round-trip: (double)(long)x.
    /// FCVTZS (FP → long, truncate toward zero) + SCVTF (long → FP).
    /// Semantically correct for |x| &lt; 2^52 (no NaN/Inf safety).
    /// Two-instruction path vs one for the baseline.
    /// </summary>
    [Benchmark(OperationsPerInvoke = N)]
    [BenchmarkCategory("Double")]
    public double LongCast_Double()
    {
        var sum = 0.0;
        foreach (var v in _doubleData)
        {
            var t = (long)v;   // FCVTZS: truncate toward zero
            sum += t;          // widening long → double (SCVTF)
        }
        return sum;
    }

    /// <summary>
    /// Generic-math path: double.Truncate via IFloatingPoint&lt;T&gt;.
    /// JIT devirtualises to the same FRINTZ/ROUNDSD instruction as Math.Truncate.
    /// </summary>
    [Benchmark(OperationsPerInvoke = N)]
    [BenchmarkCategory("Double")]
    public double GenericMath_Double()
    {
        var sum = 0.0;
        foreach (var v in _doubleData)
            sum += double.Truncate(v);
        return sum;
    }

    // ── implementations ────────────────────────────────────────────────────

    [MethodImpl(MethodImplOptions.AggressiveInlining)]
    private static float FastTruncateFloat(float x)
    {
        const uint signMask = 0x80000000u;
        const uint exponentMask = 0x7F800000u;
        const uint mantissaMask = 0x007FFFFFu;
        const int exponentBias = 127;

        var bits = BitConverter.SingleToUInt32Bits(x);
        var sign = bits & signMask;
        var exponent = (int)((bits & exponentMask) >> 23) - exponentBias;

        if (exponent < 0)
            return BitConverter.UInt32BitsToSingle(sign);
        if (exponent >= 23)
            return x;

        var mask = mantissaMask >> exponent;
        bits &= ~mask;

        return BitConverter.UInt32BitsToSingle(bits);
    }

    [MethodImpl(MethodImplOptions.AggressiveInlining)]
    private static double FastTruncateDouble(double x)
    {
        const ulong signMask = 0x8000000000000000ul;
        const ulong exponentMask = 0x7FF0000000000000ul;
        const ulong mantissaMask = 0x000FFFFFFFFFFFFFul;
        const int exponentBias = 1023;

        var bits = BitConverter.DoubleToUInt64Bits(x);
        var sign = bits & signMask;
        var exponent = (int)((bits & exponentMask) >> 52) - exponentBias;

        if (exponent < 0)
            return BitConverter.UInt64BitsToDouble(sign);
        if (exponent >= 52)
            return x;

        var mask = mantissaMask >> exponent;
        bits &= ~mask;

        return BitConverter.UInt64BitsToDouble(bits);
    }
}




